import{_ as t,a,b as o,c as d,d as r,e as n}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as p,o as l,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Přidání kanálu Dropbox","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/dropbox.md","filePath":"cs-CZ/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"cs-CZ/upload/dropbox.md"};function h(k,e,u,b,v,m){return l(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="pridani-kanalu-dropbox" tabindex="-1">Přidání kanálu Dropbox <a class="header-anchor" href="#pridani-kanalu-dropbox" aria-label="Permalink to &quot;Přidání kanálu Dropbox&quot;">​</a></h1><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Požadavek</th><th>Proč je potřeba</th></tr></thead><tbody><tr><td>Účet Dropbox</td><td>Pro přihlášení a autorizaci aplikace</td></tr><tr><td>Aplikace Dropbox</td><td>Pro vygenerování <code>App Key</code> a <code>App Secret</code></td></tr><tr><td>Vaše doména ImgBed</td><td>Pro OAuth redirect URI</td></tr><tr><td>Dostupné místo v Dropboxu</td><td>Skutečné úložiště pro soubory</td></tr></tbody></table><h2 id="nastaveni" tabindex="-1">Nastavení <a class="header-anchor" href="#nastaveni" aria-label="Permalink to &quot;Nastavení&quot;">​</a></h2><h3 id="krok-1-vytvorte-aplikaci-dropbox" tabindex="-1">Krok 1: Vytvořte aplikaci Dropbox <a class="header-anchor" href="#krok-1-vytvorte-aplikaci-dropbox" aria-label="Permalink to &quot;Krok 1: Vytvořte aplikaci Dropbox&quot;">​</a></h3><ol><li>Otevřete Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Vytvořte novou aplikaci.</li><li>Jako typ přístupu zvolte:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Dejte aplikaci rozpoznatelný název, například <code>imgbed-app</code>.</li><li>Po vytvoření otevřete detail aplikace.</li></ol><p>Doporučený typ přístupu:</p><table tabindex="0"><thead><tr><th>Typ přístupu</th><th>Doporučení</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Doporučeno. Odpovídá tomu, jak ImgBed ukládá soubory.</td></tr><tr><td><code>Full Dropbox</code></td><td>Nedoporučeno. ImgBed nepotřebuje plný přístup k celému účtu.</td></tr></tbody></table><p><img src="'+t+'" alt="Vytvoření aplikace Dropbox" loading="lazy"></p><h3 id="krok-2-pridejte-redirect-uri" tabindex="-1">Krok 2: Přidejte Redirect URI <a class="header-anchor" href="#krok-2-pridejte-redirect-uri" aria-label="Permalink to &quot;Krok 2: Přidejte Redirect URI&quot;">​</a></h3><p>V detailu aplikace Dropbox najděte nastavení OAuth nebo Redirect URI a přidejte:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Pokud administraci používáte z více domén, přidejte každou odpovídající callback URL.</p><p><img src="'+a+'" alt="Nastavení Redirect URI" loading="lazy"></p><h3 id="krok-3-nastavte-opravneni-aplikace" tabindex="-1">Krok 3: Nastavte oprávnění aplikace <a class="header-anchor" href="#krok-3-nastavte-opravneni-aplikace" aria-label="Permalink to &quot;Krok 3: Nastavte oprávnění aplikace&quot;">​</a></h3><p>Otevřete kartu <code>Permissions</code> a zapněte alespoň tyto scope:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Povinné</th><th>Účel</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Povinné</td><td>Čte informace o účtu a kvótě</td></tr><tr><td><code>files.metadata.read</code></td><td>Povinné</td><td>Čte metadata souborů a složek pro kontroly cest</td></tr><tr><td><code>files.metadata.write</code></td><td>Povinné</td><td>Vytváří složky a zapisuje metadata</td></tr><tr><td><code>files.content.write</code></td><td>Povinné</td><td>Nahrává soubory. Bez tohoto scope se objeví <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Doporučeno</td><td>Umožňuje stažení, náhled a dočasné odkazy souborů</td></tr></tbody></table><p>Po výběru scope klikněte dole na <code>Submit</code>.</p><p><img src="'+o+'" alt="Přidání oprávnění" loading="lazy"></p><p>Důležité:</p><table tabindex="0"><thead><tr><th>Situace</th><th>Co udělat</th></tr></thead><tbody><tr><td>Změnili jste scope</td><td>Spusťte autorizaci tokenu znovu a získejte nový <code>Refresh Token</code>.</td></tr><tr><td>Neprovedli jste novou autorizaci</td><td>Starý token nezíská nová oprávnění, takže upload může stále selhávat.</td></tr></tbody></table><h3 id="krok-4-zkopirujte-udaje-aplikace" tabindex="-1">Krok 4: Zkopírujte údaje aplikace <a class="header-anchor" href="#krok-4-zkopirujte-udaje-aplikace" aria-label="Permalink to &quot;Krok 4: Zkopírujte údaje aplikace&quot;">​</a></h3><p>Uložte tyto dvě hodnoty ze stránky aplikace Dropbox:</p><table tabindex="0"><thead><tr><th>Pole Dropbox</th><th>Pole ImgBed</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="krok-5-vyplnte-kanal-dropbox" tabindex="-1">Krok 5: Vyplňte kanál Dropbox <a class="header-anchor" href="#krok-5-vyplnte-kanal-dropbox" aria-label="Permalink to &quot;Krok 5: Vyplňte kanál Dropbox&quot;">​</a></h3><p>V Nastavení nahrávání zvolte <code>Dropbox</code> a vyplňte:</p><table tabindex="0"><thead><tr><th>Pole ImgBed</th><th>Co zadat</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Srozumitelný název, například <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Zatím nechte prázdné</td></tr><tr><td>Kořenový adresář</td><td>Volitelné. Výchozí je <code>imgbed</code>.</td></tr><tr><td>Poznámka</td><td>Volitelné</td></tr></tbody></table><p><img src="'+d+'" alt="Získání tokenu" loading="lazy"></p><h3 id="krok-6-ziskejte-refresh-token" tabindex="-1">Krok 6: Získejte Refresh Token <a class="header-anchor" href="#krok-6-ziskejte-refresh-token" aria-label="Permalink to &quot;Krok 6: Získejte Refresh Token&quot;">​</a></h3><ol><li>V ImgBed klikněte na <code>Get Token</code>.</li><li>Přihlaste se k účtu Dropbox, který chcete připojit.</li><li>Potvrďte autorizaci.</li><li>Callback stránka zobrazí <code>Refresh Token</code>.</li><li>Zkopírujte ho.</li><li>Vraťte se do ImgBed a vložte ho do pole <code>Refresh Token</code>.</li></ol><p><img src="'+r+'" alt="Kopírování tokenu" loading="lazy"></p><h2 id="overeni" tabindex="-1">Ověření <a class="header-anchor" href="#overeni" aria-label="Permalink to &quot;Ověření&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Očekávaný výsledek</th></tr></thead><tbody><tr><td>Karta kanálu</td><td>Kanál Dropbox se po uložení zobrazí.</td></tr><tr><td>Přepínač kanálu</td><td>Kanál lze zapnout.</td></tr><tr><td>Token je uložen</td><td>Detail ukazuje, že <code>Refresh Token</code> byl uložen.</td></tr><tr><td>Testovací upload</td><td>Testovací obrázek se objeví v aplikační složce Dropboxu.</td></tr></tbody></table><p>Pokud jsou zapnuté limity kapacity, spusťte dotaz na kvótu. Po úspěšném dotazu karta ukáže použité místo, celkové místo a čas poslední aktualizace.</p><p><img src="'+n+`" alt="Dotaz na kvótu úspěšný" loading="lazy"></p><h2 id="reseni-problemu" tabindex="-1">Řešení problémů <a class="header-anchor" href="#reseni-problemu" aria-label="Permalink to &quot;Řešení problémů&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problém</th><th>Řešení</th></tr></thead><tbody><tr><td>ImgBed hlásí neúplnou konfiguraci</td><td>Zkontrolujte, že jsou vyplněné <code>App Key</code>, <code>App Secret</code> i <code>Refresh Token</code>.</td></tr><tr><td>Autorizace proběhne, ale nezobrazí se <code>Refresh Token</code></td><td>Klikněte znovu na <code>Get Token</code> a ujistěte se, že se používá offline autorizační tok.</td></tr><tr><td>Upload selže s <code>required scope &#39;files.content.write&#39;</code></td><td>Zapněte <code>files.content.write</code>, klikněte na <code>Submit</code> a získejte nový <code>Refresh Token</code>.</td></tr><tr><td>Callback selže</td><td>Ověřte, že redirect URI je <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>Soubory nelze najít</td><td>Zkontrolujte, že aplikace Dropbox byla vytvořena v režimu <code>App folder</code>.</td></tr></tbody></table><h2 id="rychly-postup" tabindex="-1">Rychlý postup <a class="header-anchor" href="#rychly-postup" aria-label="Permalink to &quot;Rychlý postup&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otevřete Dropbox App Console</span></span>
<span class="line"><span>-&gt; Vytvořte aplikaci</span></span>
<span class="line"><span>-&gt; Vyberte App folder access</span></span>
<span class="line"><span>-&gt; Přidejte https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Zapněte account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; Volitelně zapněte files.content.read</span></span>
<span class="line"><span>-&gt; Klikněte Submit</span></span>
<span class="line"><span>-&gt; Zkopírujte App Key a App Secret</span></span>
<span class="line"><span>-&gt; Vyplňte je v ImgBed</span></span>
<span class="line"><span>-&gt; Klikněte Get Token</span></span>
<span class="line"><span>-&gt; Zkopírujte Refresh Token z callback stránky</span></span>
<span class="line"><span>-&gt; Vložte ho zpět do ImgBed a uložte</span></span></code></pre></div><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const f=p(c,[["render",h]]);export{g as __pageData,f as default};
